    def generate(self, title: str = "", category: str = "") -> str:
        """Setzt das finale SVG-Dokument zusammen."""
        if category.upper() == "NPC":
            return self.generate_mage_silhouette()
            
        svg_content = f"""<svg xmlns="http://www.w3.org/2000/svg" viewBox="{self.viewbox}" width="{self.width}" height="{self.height}">
            {self._generate_gradient_defs()}
            <!-- Background -->
            <rect width="100%" height="100%" fill="url(#bgGradient)"/>
            <!-- Random Shapes -->
            {self._generate_shapes()}
        </svg>"""
        return svg_content

    def save(self, filepath: str, title: str = "", category: str = "") -> None:
        """Speichert das SVG in eine Datei."""
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(self.generate(title, category))
